  var hasCycle = false
  for (edge <- mustEdges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val rootU = find(u)
    val rootV = find(v)
    if (rootU == rootV) {
      hasCycle = true
    } else {
      parent(rootV) = rootU
      mustCount += 1
    }
  }

