  // We want to maximize the minimal edge in the spanning tree
  // So we can binary search the answer

  var left = 1L
  var right = edges.map(e => if (e(3) == 0) e(2) * 2 else e(2)).max
  var result = -1L

  def isPossible(target: Long): Boolean = {
    val tempParent = Array.tabulate(n.toInt)(i => i)

    def tempFind(u: Int): Int = {
      if (tempParent(u) != u) tempParent(u) = tempFind(tempParent(u))
      tempParent(u)
    }

