    var connected = mustCount
    for (edge <- mustEdges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val rootU = tempFind(u)
      val rootV = tempFind(v)
      if (rootU != rootV) {
        tempParent(rootV) = rootU
