    // Process edges in descending order of their potential (after possible upgrade)
    val sortedOptional = optionalEdges.sortBy(e => -math.max(e(2), if (e(3) == 0) e(2)*2 else e(2)))

    for (edge <- sortedOptional) {
      val u = edge(0).toInt
      val v = edge(1).toInt
      val s = edge(2)
      val must = edge(3)
      val rootU = tempFind(u)
      val rootV = tempFind(v)

      if (rootU != rootV) {
